#include<bits/stdc++.h>
using namespace std;
deque <int>d;
long long ans;
int a[300001];
int main()
{
    int n;
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];  

    for(int i=1;i<=n;i++){
        while(d.size()&&a[i]>a[d.back()]){
            ans+=i-d.back()+1;
            d.pop_back();
        }
        if(d.size())ans+=i-d.back()+1;		
        d.push_back(i);        
    }
    cout<<ans;
}
